// SettleUK — Refactor Step 1: extract data/ utils/ hooks/ from App.js
// চালাতে: node setup-refactor-step1.js   (প্রজেক্টের রুট ফোল্ডারে, যেখানে package.json আছে)

const fs = require('fs');
const path = require('path');

const files = [
  {
    target: 'src/App.js',
    base64: ''
  },
  {
    target: 'src/data/stages.js',
    base64: ''
  },
  {
    target: 'src/data/documents.js',
    base64: ''
  },
  {
    target: 'src/data/guides.js',
    base64: ''
  },
  {
    target: 'src/data/packing.js',
    base64: ''
  },
  {
    target: 'src/data/universities.js',
    base64: ''
  },
  {
    target: 'src/data/costs.js',
    base64: ''
  },
  {
    target: 'src/utils/uniBand.js',
    base64: ''
  },
  {
    target: 'src/utils/format.js',
    base64: ''
  },
  {
    target: 'src/hooks/useLocalStorage.js',
    base64: ''
  },
];

// ধাপ ১: পুরানো App.js নিরাপদে ব্যাকআপ রাখা
const oldAppPath = path.join(__dirname, 'src', 'App.js');
const backupPath = path.join(__dirname, 'src', 'App.old.js');
if (fs.existsSync(oldAppPath)) {
  fs.copyFileSync(oldAppPath, backupPath);
  console.log('✔ পুরানো App.js ব্যাকআপ হলো: src/App.old.js');
}

// ধাপ ২: নতুন ফাইল বসানো
files.forEach(({ target, base64 }) => {
  const fullPath = path.join(__dirname, target);
  const dir = path.dirname(fullPath);
  fs.mkdirSync(dir, { recursive: true });
  const content = Buffer.from(base64, 'base64').toString('utf8');
  fs.writeFileSync(fullPath, content, 'utf8');
  console.log('✔ তৈরি হলো:', target);
});

console.log('\nRefactor Step 1 সম্পন্ন — App.js এখন data/utils/hooks থেকে import করছে।');
console.log('কোনো সমস্যা হলে src/App.old.js থেকে ফিরিয়ে নিতে পারবেন।');
console.log('এবার চালান: npm start');
